{"file_path":"/project/ktlint-rule-engine/src/test/kotlin/com/pinterest/ktlint/rule/engine/api/FormatRerunTest.kt","content":"package com.pinterest.ktlint.rule.engine.api

import com.pinterest.ktlint.rule.engine.core.api.ElementType.REGULAR_STRING_PART
import com.pinterest.ktlint.rule.engine.core.api.Rule
import com.pinterest.ktlint.rule.engine.core.api.Rule.VisitorModifier.RunAsLateAsPossible
import com.pinterest.ktlint.rule.engine.core.api.RuleId
import com.pinterest.ktlint.rule.engine.core.api.RuleProvider
import com.pinterest.ktlint.rule.engine.core.api.editorconfig.EditorConfig
import org.assertj.core.api.Assertions.assertThat
import org.jetbrains.kotlin.com.intellij.lang.ASTNode
import org.jetbrains.kotlin.com.intellij.psi.impl.source.tree.LeafElement
import org.junit.jupiter.api.Test

class FormatRerunTest {
    @Test
    fun `format reruns until no uncorrected auto-correctable lint violations remain and only returns the last run violations`() {
        val callbacks = mutableListOf<Pair<LintError, Boolean>>()

        val actualFormattedCode =
            KtLintRuleEngine(
                ruleProviders =
                    setOf(
                        RuleProvider { FixBarToBazRule() },
                        RuleProvider { LateIntroduceBarRule() },
                    ),
            ).format(
                Code.fromSnippet("val foo = \"foo\""),
            ) { e, corrected ->
                callbacks.add(e to corrected)
            }

        assertThat(actualFormattedCode).isEqualTo("val foo = \"baz\"")
        assertThat(callbacks).containsExactly(
            LintError(
                line = 1,
                col = 12,
                ruleId = FixBarToBazRule.RULE_ID,
                detail = FixBarToBazRule.ERROR_MESSAGE,
                canBeAutoCorrected = true,
            ) to true,
        )
    }

    @Test
    fun `format does not rerun more than three times`() {
        ToggleStringValueRule.beforeFirstNodeCalls = 0

        val actualFormattedCode =
            KtLintRuleEngine(
                ruleProviders =
                    setOf(
                        RuleProvider { ToggleStringValueRule() },
                    ),
            ).format(Code.fromSnippet("val foo = \"a\""))

        // Initial run + max 3 reruns => max 4 runs. Each run traverses the AST twice (format and lint) because the rule emits a violation.
        assertThat(ToggleStringValueRule.beforeFirstNodeCalls).isEqualTo(8)

        // 4 runs causes the string to toggle back to the original value.
        assertThat(actualFormattedCode).isEqualTo("val foo = \"a\"")
    }
}

private class LateIntroduceBarRule : Rule(
    ruleId = LateIntroduceBarRule.RULE_ID,
    about = About(),
    visitorModifiers = setOf(RunAsLateAsPossible),
) {
    override fun beforeVisitChildNodes(
        node: ASTNode,
        autoCorrect: Boolean,
        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
    ) {
        if (node.elementType == REGULAR_STRING_PART && node.text == "foo") {
            emit(node.startOffset, ERROR_MESSAGE, true)
            if (autoCorrect) {
                (node as LeafElement).rawReplaceWithText("bar")
            }
        }
    }

    companion object {
        val RULE_ID = RuleId("test:late-introduce-bar")
        const val ERROR_MESSAGE = "String value 'foo' is not allowed and will be changed to 'bar'"
    }
}

private class FixBarToBazRule : Rule(
    ruleId = FixBarToBazRule.RULE_ID,
    about = About(),
) {
    override fun beforeVisitChildNodes(
        node: ASTNode,
        autoCorrect: Boolean,
        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
    ) {
        if (node.elementType == REGULAR_STRING_PART && node.text == "bar") {
            emit(node.startOffset, ERROR_MESSAGE, true)
            if (autoCorrect) {
                (node as LeafElement).rawReplaceWithText("baz")
            }
        }
    }

    companion object {
        val RULE_ID = RuleId("test:fix-bar-to-baz")
        const val ERROR_MESSAGE = "String value 'bar' is not allowed and will be changed to 'baz'"
    }
}

private class ToggleStringValueRule : Rule(
    ruleId = ToggleStringValueRule.RULE_ID,
    about = About(),
) {
    override fun beforeFirstNode(editorConfig: EditorConfig) {
        beforeFirstNodeCalls++
    }

    override fun beforeVisitChildNodes(
        node: ASTNode,
        autoCorrect: Boolean,
        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
    ) {
        if (node.elementType != REGULAR_STRING_PART) {
            return
        }

        when (node.text) {
            "a" -> {
                emit(node.startOffset, "Toggle 'a' to 'b'", true)
                if (autoCorrect) {
                    (node as LeafElement).rawReplaceWithText("b")
                }
            }

            "b" -> {
                emit(node.startOffset, "Toggle 'b' to 'a'", true)
                if (autoCorrect) {
                    (node as LeafElement).rawReplaceWithText("a")
                }
            }
        }
    }

    companion object {
        val RULE_ID = RuleId("test:toggle-string")
        var beforeFirstNodeCalls: Int = 0
    }
}
"}

